The model decides when to call the tools based on the conversation:

 import { AIChatAgent, type OnChatMessageOptions } from "@cloudflare/ai-chat";
import { createWorkersAI } from "workers-ai-provider";
import { streamText, convertToModelMessages, tool, stepCountIs } from "ai";
import { routeAgentRequest } from "agents";
import { z } from "zod";

export class SupportAgent extends AIChatAgent<Env> {
 async onChatMessage(_onFinish: unknown, options?: OnChatMessageOptions) {
 // the client passes customerId in the request body
 // via the Agent SDK's sendMessage({ body: { customerId } })
 const customerId = options?.body?.customerId;

 // create a per-customer instance when they first show up.
 // each instance gets its own storage and vector index.
 if (customerId) {
 try {
 await this.env.SUPPORT_KB.create({
 id: `customer-${customerId}`,
 index_method: { keyword: true, vector: true }
 });
 } catch {
 // instance already exists
 }
 }

 const workersai = createWorkersAI({ binding: this.env.AI });

 const result = streamText({
 model: workersai("@cf/moonshotai/kimi-k2.5"),
 system: `You are a support agent. If you’re creating instances dynamically (e.g. per agent, per customer, per tenant), this is the binding to use.

 // create an instance 
const instance = await env.AI_SEARCH.create({
 id: "my-instance"
});

// delete an instance and all its indexed data
await env.AI_SEARCH.delete("old-instance");



 Pricing for new instances 




 New instances created as of today will get built-in storage and a vector index automatically. Every agent needs search: Coding agents search millions of files across repos, or support agents search customer tickets and internal docs. The new ai_search_namespaces binding lets you create and delete instances at runtime from your Worker, so you can spin up one per agent, per customer, or per language without redeployment.

Classified impact band: medium. Affected layer signal: edge — cdn.

